<div class="gsr-top"><div class="gsr-stat"><strong>Room</strong><span data-room>1</span></div><div class="gsr-stat"><strong>Gravity</strong><span data-gravity>Down</span></div><div class="gsr-stat"><strong>Moves</strong><span data-steps>12</span></div><div class="gsr-stat"><strong>Goal</strong><span>Reach each door</span></div></div>
<div class="gsr-board" data-board></div>
<div class="gsr-panel"><div class="gsr-btns"><button class="gsr-btn" data-left>Left</button><button class="gsr-btn" data-right>Right</button><button class="gsr-btn" data-flip>Flip Gravity</button><button class="gsr-btn" data-restart>Restart</button></div><p data-log></p></div>
</div>
